class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int[] primes = new int[n];
        int primeCount = 0;
        for (int i = 2; i <= 1000; i++) {
            boolean isPrime = true;
            for (int j = 2; j * j <= i; j++) {
                if (i % j == 0) {
                    isPrime = false;
                    break;
                }
            }
            if (isPrime) {
                primes[primeCount++] = i;
            }
        }
        int[] dp = new int[n + 1];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j < primeCount && primes[j] * primes[j] <= nums[i - 1]; j++) {
                if (nums[i - 1] % primes[j] == 0) {
                    dp[i] = Math.min(dp[i], dp[i - 1] + 1);
                }
            }
            for (int j = 0; j < primeCount && primes[j] * primes[j] <= nums[i - 1]; j++) {
                if (nums[i - 1] % primes[j] == 0) {
                    int k = i - 1;
                    while (k >= 0 && nums[k] % primes[j] == 0) {
                        k--;
                    }
                    dp[i] = Math.min(dp[i], dp[k + 1] + 1);
                }
            }
            if (dp[i] > maxC) {
                dp[i] = Integer.MAX_VALUE;
            }
        }
        int ans = Integer.MAX_VALUE;
        for (int i = 0; i <= n; i++) {
            ans = Math.min(ans, dp[i]);
        }
        return ans == Integer.MAX_VALUE ? 0 : ans;
    }
}
